import {
  forwardRef,
  type PropsWithChildren,
  useContext,
  type CSSProperties,
} from 'react';

import { contentGridStaticStyles } from './ContentGrid.sty.js';
import { VALUE_FONT_CSS_TOKEN } from '../constants.js';
import { FontSizeContext } from '../contexts/font-size.context.js';

interface ContentProps {
  color: string;
  gridTemplate: string;
}

export const ContentGrid = forwardRef<
  HTMLDivElement,
  PropsWithChildren<ContentProps>
>(({ color, gridTemplate, children }, forwardedRef) => {
  const { fontSize } = useContext(FontSizeContext);

  return (
    <div
      className={contentGridStaticStyles}
      style={
        {
          gridTemplate,
          color,
          [VALUE_FONT_CSS_TOKEN]: fontSize,
        } as CSSProperties
      }
      ref={forwardedRef}
      data-testid="single-value-chart-content"
    >
      {children}
    </div>
  );
});
